  ('judicial-de09bf8b-moex-00005', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-114-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '關於不作為犯之敘述，下列何者錯誤？', '["刑法第293條第1項之遺棄罪為不作為犯", "不純正不作為犯之因果關係為假設的因果關係", "不純正不作為犯之成立，行為人需法律上有防止之義務，能防止而不防止", "因自己行為致有發生犯罪結果之危險者，負防止其發生之義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:18+00:00", "source_pdf_sha1": "fde970b6d70a", "answer_pdf_sha1": "3fa941030e42", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
